    20→function validateEnv() {
    21→  const missing = REQUIRED_ENV.filter(key => !process.env[key]);
    22→  if (missing.length > 0) {
    23→    console.error(`\n[CRITICAL] Missing required environment variables: ${missing.join(', ')}`);
