    42→  ];
    43→  const lsMissing = lsKeys.filter(key => !process.env[key]);
    44→  if (lsMissing.length > 0) {
    45→    console.warn(`[payments] Lemon Squeezy incomplete — checkout/webhooks may fail: ${lsMissing.join(', ')}`);
