     9→const { pool } = require('./db');
    10→const fs = require('fs');
    11→const { resetMonthlyCredits } = require('./storage');
    12→
    13→function buildApp() {
    14→  const app = express();
    15→
    16→  const allowedOrigins = [
    17→    'http://localhost:5000',
    18→    'http://localhost:5001',
    19→    process.env.FRONTEND_URL,
    20→    ...(process.env.REPLIT_DOMAINS
    21→      ? process.env.REPLIT_DOMAINS.split(',').map(d => `https://${d.trim()}`)
    22→      : []),
    23→    process.env.REPLIT_DEV_DOMAIN ? `https://${process.env.REPLIT_DEV_DOMAIN}` : null
    24→  ].filter(Boolean);
    25→
    26→  app.use(cors({
    27→    origin: (origin, cb) => {
    28→      if (!origin || allowedOrigins.some(o => origin.startsWith(o))) return cb(null, true);
    29→      cb(null, true);
    30→    },
    31→    credentials: true
    32→  }));
    33→
    34→  // Required for FFmpeg WebAssembly SharedArrayBuffer support
    35→  app.use((req, res, next) => {
    36→    res.setHeader('Cross-Origin-Opener-Policy', 'same-origin');
    37→    res.setHeader('Cross-Origin-Embedder-Policy', 'require-corp');
    38→    next();
    39→  });
    40→
    41→  app.use('/api/ls/webhook', express.raw({ type: 'application/json' }));
    42→  app.use(express.json({ limit: '10mb' }));
    43→
    44→  return app;
    45→}
