    47→async function initDb(app) {
    48→  const schema = fs.readFileSync(path.join(__dirname, 'schema.sql'), 'utf8');
    49→  let retries = 5;
    50→  while (retries > 0) {
    51→    try {
    52→      await pool.query(schema);
    53→      console.log('Database schema initialized');
    54→      return;
    55→    } catch (err) {
    56→      console.warn(`Database connection failed (${retries} retries left):`, err.message);
    57→      retries -= 1;
    58→      if (retries === 0) throw err;
    59→      await new Promise(resolve => setTimeout(resolve, 3000));
    60→    }
    61→  }
    62→}
    63→
    64→async function mountRoutes(app) {
    65→  await setupAuth(app);
    66→  app.use('/api/user', userRoutes);
    67→  app.use('/api/admin', adminRoutes);
    68→  app.use('/api/ls', lemonsqueezyRoutes);
    69→  app.use('/api/gopay', gopayRoutes);
    70→  app.get('/api/health', (req, res) => res.json({ ok: true }));
    71→
    72→  // Serve static files from the built dist directory
    73→  app.use(express.static(path.join(__dirname, '../dist')));
    74→  
    75→  // Wildcard fallback to serve index.html for SPA routing (React Router)
    76→  app.get(/(.*)/, (req, res, next) => {
    77→    if (req.path.startsWith('/api')) {
    78→      return next();
    79→    }
    80→    res.sendFile(path.join(__dirname, '../dist/index.html'));
    81→  });
    82→}
    83→
    84→let _initPromise = null;
    85→let _app = null;
    86→
    87→async function getApp() {
    88→  if (_app) return _app;
    89→  if (!_initPromise) {
    90→    _initPromise = (async () => {
    91→      const app = buildApp();
    92→      await initDb(app);
    93→      await mountRoutes(app);
    94→      _app = app;
    95→      return app;
    96→    })();
    97→  }
    98→  return _initPromise;
    99→}
   100→
   101→module.exports = { getApp, buildApp, initDb, mountRoutes, resetMonthlyCredits };
