     1→const session        = require('express-session');
     2→const connectPg      = require('connect-pg-simple');
     3→const passport       = require('passport');
     4→const GoogleStrategy = require('passport-google-oauth20').Strategy;
     5→const { pool }       = require('./db');
     6→const { upsertUser, getUserById } = require('./storage');
     7→
     8→/* ── Session ─────────────────────────────────────────────── */
     9→function getSession() {
    10→  const sessionTtl = 7 * 24 * 60 * 60 * 1000; // 7 days
    11→  const PgStore    = connectPg(session);
    12→  const sessionStore = new PgStore({
    13→    pool,
    14→    createTableIfMissing: false,
    15→    ttl: sessionTtl / 1000,
    16→    tableName: 'sessions',
    17→  });
    18→
    19→  const isProduction = process.env.NODE_ENV === 'production';
    20→
    21→  return session({
    22→    secret: process.env.SESSION_SECRET || 'typebeatz-dev-secret-change-in-prod',
    23→    store: sessionStore,
    24→    resave: false,
    25→    saveUninitialized: false,
    26→    cookie: {
    27→      httpOnly: true,
    28→      secure: isProduction,
    29→      sameSite: isProduction ? 'none' : 'lax',
    30→      maxAge: sessionTtl,
    31→    },
    32→  });
    33→}
    34→
    35→/* ── Google OAuth Strategy ───────────────────────────────── */
    36→function getCallbackURL() {
    37→  if (process.env.APP_URL)    return `${process.env.APP_URL}/api/callback`;
    38→  if (process.env.REPLIT_DEV_DOMAIN) return `https://${process.env.REPLIT_DEV_DOMAIN}/api/callback`;
    39→  if (process.env.REPLIT_DOMAINS) return `https://${process.env.REPLIT_DOMAINS.split(',')[0].trim()}/api/callback`;
    40→  if (process.env.VERCEL_URL) return `https://${process.env.VERCEL_URL}/api/callback`;
    41→  return 'http://localhost:3001/api/callback';
    42→}
    43→
    44→if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
    45→  passport.use(new GoogleStrategy(
    46→    {
    47→      clientID:     process.env.GOOGLE_CLIENT_ID,
    48→      clientSecret: process.env.GOOGLE_CLIENT_SECRET,
    49→      callbackURL:  getCallbackURL(),
    50→    },
    51→    async (_accessToken, _refreshToken, profile, done) => {
    52→      try {
    53→        const email        = profile.emails?.[0]?.value || '';
    54→        const firstName    = profile.name?.givenName  || '';
    55→        const lastName     = profile.name?.familyName || '';
    56→        const profileImage = profile.photos?.[0]?.value || '';
    57→
    58→        const user = await upsertUser({
    59→          id: profile.id,
    60→          email,
    61→          first_name:        firstName,
    62→          last_name:         lastName,
    63→          profile_image_url: profileImage,
    64→        });
    65→
    66→        return done(null, user);
    67→      } catch (err) {
    68→        return done(err);
    69→      }
    70→    }
    71→  ));
    72→} else {
    73→  console.warn('[auth] Google OAuth strategy not registered — GOOGLE_CLIENT_ID/SECRET missing');
    74→}
    75→
    76→passport.serializeUser((user, done)   => done(null, user.id));
    77→passport.deserializeUser(async (id, done) => {
    78→  try {
    79→    const user = await getUserById(String(id));
    80→    done(null, user || false);
    81→  } catch (err) {
    82→    done(err);
    83→  }
    84→});
    85→
    86→/* ── Mount auth routes ───────────────────────────────────── */
    87→async function setupAuth(app) {
    88→  app.set('trust proxy', 1);
    89→  app.use(getSession());
    90→  app.use(passport.initialize());
    91→  app.use(passport.session());
    92→
    93→  /* Kick off Google login */
    94→  app.get('/api/login', (req, res, next) => {
    95→    if (!process.env.GOOGLE_CLIENT_ID || !process.env.GOOGLE_CLIENT_SECRET) {
    96→      return res.status(503).json({ message: 'Google OAuth not configured. Please set GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET.' });
    97→    }
    98→    passport.authenticate('google', { scope: ['profile', 'email'] })(req, res, next);
    99→  });
   100→
   101→  /* Google redirects here after the user grants access */
   102→  app.get('/api/callback',
   103→    passport.authenticate('google', { failureRedirect: '/login' }),
   104→    (req, res) => {
   105→      // Store userId for backward-compat with isAuthenticated middleware
   106→      req.session.userId = req.user?.id;
   107→      req.session.user   = { id: req.user?.id, email: req.user?.email };
   108→      res.redirect('/app');
   109→    }
   110→  );
   111→
   112→  app.get('/api/logout', (req, res) => {
   113→    req.logout(() => {
   114→      req.session.destroy(() => res.redirect('/'));
   115→    });
   116→  });
   117→}
   118→
   119→/* ── Auth middleware ─────────────────────────────────────── */
   120→const isAuthenticated = (req, res, next) => {
   121→  // Support both passport session (req.user) and manual userId session
   122→  if (req.isAuthenticated?.() || req.session?.userId) {
   123→    if (!req.user && req.session?.user) req.user = req.session.user;
   124→    return next();
   125→  }
   126→  return res.status(401).json({ message: 'Unauthorized' });
   127→};
   128→
   129→const isAdmin = async (req, res, next) => {
   130→  await isAuthenticated(req, res, async () => {
   131→    const dbUser = await getUserById(String(req.user?.id));
   132→    if (dbUser?.role !== 'admin') {
   133→      return res.status(403).json({ message: 'Forbidden' });
   134→    }
   135→    req.dbUser = dbUser;
   136→    next();
   137→  });
   138→};
   139→
   140→module.exports = { setupAuth, isAuthenticated, isAdmin };
