     1→const { pool } = require('./db');
     2→
     3→async function upsertUser(userData) {
     4→  const { id, email, first_name, last_name, profile_image_url } = userData;
     5→  const result = await pool.query(
     6→    `INSERT INTO users (id, email, first_name, last_name, profile_image_url, updated_at)
     7→     VALUES ($1, $2, $3, $4, $5, NOW())
     8→     ON CONFLICT (id) DO UPDATE SET
     9→       email = EXCLUDED.email,
    10→       first_name = EXCLUDED.first_name,
    11→       last_name = EXCLUDED.last_name,
    12→       profile_image_url = EXCLUDED.profile_image_url,
    13→       updated_at = NOW()
    14→     RETURNING *`,
    15→    [id, email, first_name, last_name, profile_image_url]
    16→  );
    17→  const user = result.rows[0];
    18→
    19→  // Ensure credits row exists for new users
    20→  await pool.query(
    21→    `INSERT INTO credits (user_id, credits_remaining, credits_used_this_month)
    22→     VALUES ($1, 5, 0)
    23→     ON CONFLICT (user_id) DO NOTHING`,
    24→    [id]
    25→  );
    26→
    27→  return user;
    28→}
    29→ 
    30→async function updateUserProfile(userId, { first_name, last_name, producer_name, profile_image_url }) {
    31→  const result = await pool.query(
    32→    `UPDATE users
    33→     SET first_name = COALESCE($1, first_name),
    34→         last_name = COALESCE($2, last_name),
    35→         producer_name = COALESCE($3, producer_name),
    36→         profile_image_url = COALESCE($4, profile_image_url),
    37→         updated_at = NOW()
    38→     WHERE id = $5
    39→     RETURNING *`,
    40→    [first_name ?? null, last_name ?? null, producer_name ?? null, profile_image_url ?? null, userId]
    41→  );
    42→  return result.rows[0];
    43→}
    44→
    45→async function getUserById(id) {
    46→  const result = await pool.query('SELECT * FROM users WHERE id = $1', [id]);
    47→  return result.rows[0] || null;
    48→}
    49→
    50→async function getAllUsers() {
    51→  const result = await pool.query(`
    52→    SELECT u.*, c.credits_remaining, c.credits_used_this_month, c.last_reset_at,
    53→           s.status as subscription_status, s.current_period_end
    54→    FROM users u
    55→    LEFT JOIN credits c ON c.user_id = u.id
    56→    LEFT JOIN subscriptions s ON s.user_id = u.id
    57→    ORDER BY u.created_at DESC
    58→  `);
    59→  return result.rows;
    60→}
    61→
    62→async function getUserCredits(userId) {
    63→  const result = await pool.query(
    64→    'SELECT * FROM credits WHERE user_id = $1',
    65→    [userId]
    66→  );
    67→  if (!result.rows[0]) {
    68→    // Create credits row if missing
    69→    const insert = await pool.query(
    70→      `INSERT INTO credits (user_id, credits_remaining, credits_used_this_month)
    71→       VALUES ($1, 5, 0) RETURNING *`,
    72→      [userId]
    73→    );
    74→    return insert.rows[0];
    75→  }
    76→  return result.rows[0];
    77→}
    78→
    79→async function deductCredits(userId, count = 1) {
