   185→function generateCode() {
   186→  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
   187→  let code = '';
   188→  for (let i = 0; i < 6; i++) {
   189→    code += chars[Math.floor(Math.random() * chars.length)];
   190→  }
   191→  return code;
   192→}
