   194→async function ensureReferralCode(userId) {
   195→  const existing = await pool.query('SELECT referral_code FROM users WHERE id = $1', [userId]);
   196→  if (existing.rows[0]?.referral_code) return existing.rows[0].referral_code;
   197→
   198→  let code, attempts = 0;
   199→  while (attempts < 10) {
   200→    code = generateCode();
   201→    try {
   202→      const r = await pool.query(
   203→        'UPDATE users SET referral_code = $1 WHERE id = $2 AND referral_code IS NULL RETURNING referral_code',
   204→        [code, userId]
   205→      );
   206→      if (r.rows[0]) return r.rows[0].referral_code;
   207→    } catch (e) {
   208→      if (e.code !== '23505') throw e;
   209→    }
   210→    attempts++;
   211→  }
   212→  const final = await pool.query('SELECT referral_code FROM users WHERE id = $1', [userId]);
   213→  return final.rows[0]?.referral_code;
   214→}
   215→
   216→async function applyReferralCode(newUserId, code) {
   217→  const normalizedCode = code.trim().toUpperCase();
   218→
   219→  const alreadyReferred = await pool.query(
   220→    'SELECT referred_by FROM users WHERE id = $1', [newUserId]
   221→  );
   222→  if (alreadyReferred.rows[0]?.referred_by) {
   223→    return { success: false, reason: 'already_referred' };
   224→  }
   225→
   226→  const referrer = await pool.query(
   227→    'SELECT id FROM users WHERE referral_code = $1', [normalizedCode]
   228→  );
   229→  if (!referrer.rows[0]) return { success: false, reason: 'invalid_code' };
   230→  const referrerId = referrer.rows[0].id;
   231→  if (referrerId === newUserId) return { success: false, reason: 'self_referral' };
   232→
   233→  await pool.query('BEGIN');
   234→  try {
   235→    await pool.query(
   236→      'UPDATE users SET referred_by = $1 WHERE id = $2',
   237→      [normalizedCode, newUserId]
   238→    );
   239→    await pool.query(
   240→      `INSERT INTO referral_uses (referrer_user_id, new_user_id) VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   241→      [referrerId, newUserId]
   242→    );
   243→    await pool.query(
   244→      `UPDATE credits SET credits_remaining = credits_remaining + 1, updated_at = NOW() WHERE user_id = $1`,
   245→      [newUserId]
   246→    );
   247→    await pool.query(
   248→      `UPDATE credits SET credits_remaining = credits_remaining + 1, updated_at = NOW() WHERE user_id = $1`,
   249→      [referrerId]
   250→    );
   251→    await pool.query('COMMIT');
   252→    return { success: true, referrerId };
   253→  } catch (e) {
   254→    await pool.query('ROLLBACK');
   255→    throw e;
   256→  }
   257→}
   258→
   259→async function getReferralStats(userId) {
   260→  const code = await ensureReferralCode(userId);
   261→  const uses = await pool.query(
   262→    'SELECT COUNT(*) as count FROM referral_uses WHERE referrer_user_id = $1',
   263→    [userId]
   264→  );
   265→  return { code, uses: parseInt(uses.rows[0].count, 10) };
   266→}
