   362→  }
   363→
   364→  let payload;
   365→  try {
   366→    payload = JSON.parse(req.body.toString());
   367→  } catch (err) {
   368→    console.error('Lemon Squeezy webhook JSON parse error:', err);
   369→    return res.status(400).send('Invalid JSON payload');
   370→  }
   371→
   372→  try {
   373→    const eventName = payload?.meta?.event_name;
   374→    const data = payload?.data;
   375→    const attributes = data?.attributes;
   376→
