   378→      const customUserId = payload?.meta?.custom_data?.user_id;
   379→      if (customUserId) return String(customUserId);
   380→
   381→      // Fallback: look up by subscription ID in database
   382→      const subId = `ls_${data?.id}`;
   383→      const r = await pool.query(
