    94→function WordReveal({ text, style, className }) {
    95→  const ref = useRef(null);
    96→  const [visible, setVisible] = useState(false);
    97→
    98→  useEffect(() => {
    99→    const el = ref.current;
   100→    if (!el) return;
   101→    const obs = new IntersectionObserver(([entry]) => {
   102→      if (entry.isIntersecting) { setVisible(true); obs.disconnect(); }
   103→    }, { threshold: 0.2 });
   104→    obs.observe(el);
   105→    return () => obs.disconnect();
   106→  }, []);
   107→
   108→  const words = String(text).split(' ');
   109→  return (
   110→    <span ref={ref} className={className} style={style}>
   111→      {words.map((word, i) => (
   112→        <span key={i} style={{
   113→          display: 'inline-block',
   114→          opacity: visible ? 1 : 0,
   115→          transform: visible ? 'translateY(0)' : 'translateY(10px)',
   116→          transition: `opacity 0.5s ease ${i * 60}ms, transform 0.5s ease ${i * 60}ms`,
   117→          marginRight: i < words.length - 1 ? '0.2em' : 0,
   118→        }}>
   119→          {word}
   120→        </span>
   121→      ))}
   122→    </span>
   123→  );
   124→}
