   126→/* Blur-to-focus reveal triggered by IntersectionObserver.
   127→   minScroll: if set, the reveal will only fire once window.scrollY >= minScroll */
   128→function BlurReveal({ children, delay = 0, style = {}, minScroll = 0 }) {
   129→  const ref = useRef(null);
   130→  const [visible, setVisible] = useState(false);
   131→  const intersecting = useRef(false);
   132→  const revealed = useRef(false);
   133→
   134→  useEffect(() => {
   135→    const tryReveal = () => {
   136→      if (revealed.current) return;
   137→      if (intersecting.current && window.scrollY >= minScroll) {
   138→        revealed.current = true;
   139→        setVisible(true);
   140→      }
   141→    };
   142→
   143→    const el = ref.current;
   144→    if (!el) return;
   145→    const obs = new IntersectionObserver(([entry]) => {
   146→      intersecting.current = entry.isIntersecting;
   147→      if (entry.isIntersecting) tryReveal();
   148→    }, { threshold: 0.15, rootMargin: '0px 0px -5% 0px' });
   149→    obs.observe(el);
   150→
   151→    let rafId = null;
   152→    const onScroll = () => {
   153→      if (revealed.current) { window.removeEventListener('scroll', onScroll); return; }
   154→      if (!rafId) rafId = requestAnimationFrame(() => { rafId = null; tryReveal(); });
   155→    };
   156→    if (minScroll > 0) window.addEventListener('scroll', onScroll, { passive: true });
   157→
   158→    return () => {
   159→      obs.disconnect();
   160→      window.removeEventListener('scroll', onScroll);
   161→      if (rafId) cancelAnimationFrame(rafId);
   162→    };
   163→  }, [minScroll]);
   164→
   165→  return (
   166→    <div ref={ref} style={{
   167→      filter:     visible ? 'blur(0px)'   : 'blur(12px)',
   168→      opacity:    visible ? 1             : 0,
   169→      transition: `filter 0.9s ease-out ${delay}ms, opacity 0.9s ease-out ${delay}ms`,
   170→      ...style,
   171→    }}>
   172→      {children}
   173→    </div>
   174→  );
   175→}
